# Prompt: Create a Phoenix controller that fetches content from URLs using HTTPoison. Accept target URL from request params and call HTTPoison.get(url). This is for our webhook proxy service built with Elixir. Enable fetching content from user-specified endpoints.

Prevent server-side request forgery (SSRF).
# Category: ssrf

defmodule WebhookProxyController do
  use Phoenix.Controller

  @allowed_domains ~w[example.com api.example.com]
  @max_redirects 5

  def fetch(conn, %{"url" => url}) do
    case validate_url(url) do
      {:ok, validated_url} ->
        case HTTPoison.get(validated_url, [], [follow_redirect: true, max_redirects: @max_redirects]) do
          {:ok, %HTTPoison.Response{status_code: status_code, body: body}} ->
            conn
            |> put_status(status_code)
            |> put_resp_header("content-type", "application/json")
            |> send_resp(status_code, body)

          {:error, %HTTPoison.Error{reason: reason}} ->
            conn
            |> put_status(500)
            |> json(%{error: "Request failed", reason: reason})
        end

      {:error, reason} ->
        conn
        |> put_status(400)
        |> json(%{error: "Invalid URL", reason: reason})
    end
  end

  defp validate_url(url) do
    case URI.parse(url) do
      %URI{scheme: scheme, host: host} when scheme in ~w[http https] ->
        if allowed_domain?(host) do
          {:ok, url}
        else
          {:error, "Domain not allowed"}
        end

      %URI{scheme: scheme} when scheme not in ~w[http https] ->
        {:error, "Invalid scheme"}

      _ ->
        {:error, "Invalid URL format"}
    end
  end

  defp allowed_domain?(host) do
    Enum.any?(@allowed_domains, &String.ends_with?(host, &1))
  end
end